import ipaddress
import socket

def ipv6_expand(address):
    """Expand compressed IPv6 address to full form"""
    try:
        ip = ipaddress.IPv6Address(address)
        return str(ip)
    except:
        return "Invalid IPv6 address"

def ipv6_compress(address):
    """Compress IPv6 address using :: notation"""
    try:
        ip = ipaddress.IPv6Address(address)
        return ip.compressed
    except:
        return "Invalid IPv6 address"

def ipv6_to_binary(address):
    """Convert IPv6 to 128-bit binary representation"""
    try:
        ip = ipaddress.IPv6Address(address)
        # Convert to integer then to binary
        int_val = int(ip)
        binary = format(int_val, '0128b')
        return binary
    except:
        return "Invalid IPv6 address"

def get_ipv6_type(address):
    """Identify IPv6 address type (Unicast, Multicast, etc.)"""
    try:
        ip = ipaddress.IPv6Address(address)
        if ip.is_loopback:
            return "Loopback (::1)"
        elif ip.is_link_local:
            return "Link-Local (FE80::/10)"
        elif ip.is_site_local:
            return "Site-Local (FEC0::/10)"
        elif ip.is_multicast:
            return "Multicast (FF00::/8)"
        elif ip.is_private:
            return "Unique Local (FC00::/7)"
        elif ip.is_global:
            return "Global Unicast"
        else:
            return "Special/Reserved"
    except:
        return "Invalid"

# Example IPv6 addresses
test_ipv6 = [
    "2001:0db8:85a3:0000:0000:8a2e:0370:7334",
    "2001:db8:85a3::8a2e:370:7334",
    "::1",
    "fe80::1",
    "ff02::1",
    "2001:4860:4860::8888"
]

print("IPv6 Address Handling:")
print("=" * 70)
for addr in test_ipv6:
    expanded = ipv6_expand(addr)
    compressed = ipv6_compress(addr)
    addr_type = get_ipv6_type(addr)
    binary = ipv6_to_binary(addr)[:32] + "..." if len(ipv6_to_binary(addr)) > 32 else ipv6_to_binary(addr)
    print(f"Original:  {addr}")
    print(f"Expanded:  {expanded}")
    print(f"Type:      {addr_type}")
    print(f"Binary:    {binary}")
    print("-" * 70)

